    grossContractValue: totalGVC,
    netIncome,
    totalCollected,
    totalMaintenanceCosts: totalCosts,
    grossROI: parseFloat(grossROI.toFixed(1)) || 0,
    netROI: parseFloat(netROI.toFixed(1)) || 0,
